diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 9f034aba874a..50c569c85b31 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -3344,6 +3344,79 @@ Instruction *InstCombinerImpl::foldICmpBinOpEqualityWithConstant(
         Neg->takeName(BO);
         return new ICmpInst(Pred, BOp0, Neg);
       }
+    } else {
+      // (add (ext i1 X), (ext i1 Y)) ==/!= C --> (logic op on X, Y)
+      Value *X, *Y;
+      bool IsZext0 = match(BOp0, m_ZExt(m_Value(X)));
+      bool IsSext0 = !IsZext0 ? match(BOp0, m_SExt(m_Value(X))) : false;
+      bool IsZext1 = match(BOp1, m_ZExt(m_Value(Y)));
+      bool IsSext1 = !IsZext1 ? match(BOp1, m_SExt(m_Value(Y))) : false;
+      if ((IsZext0 || IsSext0) && (IsZext1 || IsSext1) &&
+          X->getType()->isIntOrIntVectorTy(1) &&
+          Y->getType()->isIntOrIntVectorTy(1)) {
+        // The sum of two extended booleans can be:
+        //   zext+zext: 0, 1, 2
+        //   sext+sext: 0, -1, -2
+        //   mixed: -1, 0, 1
+        // Map each valid constant to a logical operation.
+        if (IsZext0 && IsZext1) {
+          if (C.isZero()) {
+            Value *V = Builder.CreateOr(X, Y);
+            return isICMP_NE ? replaceInstUsesWith(Cmp, V)
+                             : BinaryOperator::CreateNot(V);
+          }
+          if (C == 1) {
+            Value *V = Builder.CreateXor(X, Y);
+            return isICMP_NE ? BinaryOperator::CreateNot(V)
+                             : replaceInstUsesWith(Cmp, V);
+          }
+          if (C == 2) {
+            Value *V = Builder.CreateAnd(X, Y);
+            return isICMP_NE ? BinaryOperator::CreateNot(V)
+                             : replaceInstUsesWith(Cmp, V);
+          }
+        } else if (IsSext0 && IsSext1) {
+          if (C.isZero()) {
+            Value *V = Builder.CreateXor(X, Y);
+            return isICMP_NE ? replaceInstUsesWith(Cmp, V)
+                             : BinaryOperator::CreateNot(V);
+          }
+          if (C.isAllOnes()) {
+            Value *V = Builder.CreateXor(X, Y);
+            return isICMP_NE ? BinaryOperator::CreateNot(V)
+                             : replaceInstUsesWith(Cmp, V);
+          }
+          if (C == -2) {
+            Value *V = Builder.CreateAnd(X, Y);
+            return isICMP_NE ? BinaryOperator::CreateNot(V)
+                             : replaceInstUsesWith(Cmp, V);
+          }
+        } else {
+          // Mixed sext+zext
+          Value *SextOp = IsSext0 ? X : Y;
+          Value *ZextOp = IsSext0 ? Y : X;
+          if (C.isZero()) {
+            Value *V = Builder.CreateXor(X, Y);
+            return isICMP_NE ? replaceInstUsesWith(Cmp, V)
+                             : BinaryOperator::CreateNot(V);
+          }
+          if (C.isOne()) {
+            Value *NotSext = Builder.CreateNot(SextOp);
+            Value *V = Builder.CreateAnd(NotSext, ZextOp);
+            return isICMP_NE ? BinaryOperator::CreateNot(V)
+                             : replaceInstUsesWith(Cmp, V);
+          }
+          if (C.isAllOnes()) {
+            Value *NotZext = Builder.CreateNot(ZextOp);
+            Value *V = Builder.CreateAnd(SextOp, NotZext);
+            return isICMP_NE ? BinaryOperator::CreateNot(V)
+                             : replaceInstUsesWith(Cmp, V);
+          }
+        }
+        // C is not a possible sum value for this combination of extends.
+        return replaceInstUsesWith(Cmp,
+            ConstantInt::get(Cmp.getType(), isICMP_NE));
+      }
     }
     break;
   }

